pages\\admin.astro.frontmatter:
import '../styles/global.css';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import jobsData from '../data/jobs.json';
import homepageData from '../data/homepage.json';
import aboutData from '../data/about.json';
import faqData from '../data/faq.json';
import programsData from '../data/programs.json';
import couponConfigData from '../data/coupon-config.json';

export const prerender = false;

// Authenticate session
let authenticated = false;
let loginError = '';

if (Astro.cookies.has('admin_session')) {
    const sessionCookie = Astro.cookies.get('admin_session');
    if (sessionCookie && sessionCookie.value === 'authenticated') {
        authenticated = true;
    }
}

// Handle login post request
if (Astro.request.method === 'POST') {
    try {
        const formData = await Astro.request.formData();
        const action = formData.get('action');

        if (action === 'login') {
            const username = formData.get('username');
            const password = formData.get('password');

            if (username === 'admin' && password === 'Xziant@123') {
                Astro.cookies.set('admin_session', 'authenticated', {
                    path: '/',
                    httpOnly: true,
                    sameSite: 'strict',
                    maxAge: 86400
                });
                return Astro.redirect('/admin');
            } else {
                loginError = 'Invalid credentials. Please try again.';
            }
        } else if (action === 'logout') {
            Astro.cookies.delete('admin_session', { path: '/' });
            return Astro.redirect('/admin');
        }
    } catch (e) {
        loginError = 'An error occurred during authentication.';
    }
}

